############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(A.5.4.11) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGchoicemacros.pl", "contextArbitraryString.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ ($a, $b) = map{$_/100} ((-999..-1)[NchooseK(99,2)]); Context("ArbitraryString"); $operator = ($a > $b) ? '>' : '<'; $answer = Compute($operator)->cmp( checker => sub { my ($correct,$student,$ans) = @_; $correct = $correct->value; $student = $student->value; if ($student =~ /^~~s*$correct~~s*$/) {return 1} elsif ($student !~ /^~~s*>~~s*$/ && $student !~ /^~~s*<~~s*$/ && $student !~ /^~~s*=~~s*$/) {Value->Error("Answer with >, <, or =.")} else {return 0}; } );
############################################################ # Body ############################################################
BEGIN_PGML Decide if one given number is greater than, less than, or equal to another given number.
[`[$a]`] [_]{$answer}{3} [`[$b]`]
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
